import collections
import heapq

class Solution:
    def reorganizeString(self, s: str) -> str:
        n = len(s)
        counts = collections.Counter(s)

        pq = []
        for char, freq in counts.items():
            if freq > (n + 1) // 2:
                return ""
            heapq.heappush(pq, (-freq, char))

        result = []
        prev_item = (0, '') 

        while pq:
            curr_freq, curr_char = heapq.heappop(pq)

            result.append(curr_char)
            curr_freq += 1

            if prev_item[0] < 0:
                heapq.heappush(pq, prev_item)

            if curr_freq < 0:
                prev_item = (curr_freq, curr_char)
            else:
                prev_item = (0, '')

        return "".join(result) if len(result) == n else ""
